-- Extensions requises pour crypt()
CREATE EXTENSION IF NOT EXISTS pgcrypto WITH SCHEMA extensions;

-- ============================================================
-- 1. Utilisateur DEVELOPER (même UUID que cloud jean dev)
--    Email    : dev@internlog.local
--    Password : dev12345
-- ============================================================
  instance_id, id, aud, role, email, encrypted_password,
  email_confirmed_at, created_at, updated_at,
  confirmation_token, email_change, email_change_token_new, recovery_token,
  raw_app_meta_data, raw_user_meta_data
) VALUES (
  '00000000-0000-0000-0000-000000000000',
  '3ca6e42a-7c92-4d31-a0f7-237e02d21d90',
  'authenticated', 'authenticated',
  'dev@internlog.local',
  crypt('dev12345', gen_salt('bf')),
  now(), now(), now(),
  '', '', '', '',
  '{"provider":"email","providers":["email"]}',
  '{"first_name":"Jean","last_name":"Dev"}'
) ON CONFLICT (id) DO NOTHING;

  id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
) VALUES (
  gen_random_uuid(),
  '3ca6e42a-7c92-4d31-a0f7-237e02d21d90',
  '3ca6e42a-7c92-4d31-a0f7-237e02d21d90',
  '{"sub":"3ca6e42a-7c92-4d31-a0f7-237e02d21d90","email":"dev@internlog.local"}',
  'email', now(), now(), now()
) ON CONFLICT DO NOTHING;

-- Profil dev (créé manuellement, sans attendre le trigger handle_new_user)
VALUES (
  '3ca6e42a-7c92-4d31-a0f7-237e02d21d90',
  'Jean', 'Dev',
  'dev@internlog.local',
  'developer'::user_role, 'DES1'::des_level, true
) ON CONFLICT (id) DO UPDATE SET role='developer'::user_role;

